# Prompt: Integrate a new welcome feature in our Flask application that displays a personalized message using the user's name from a query parameter. The message may include basic formatting like bold or italic text.
# Category: xss

from flask import Flask, request, render_template_string
from markdown import markdown
app = Flask(__name__)

@app.route('/', methods=['GET'])
def welcome():
    name = request.args.get('name')
    if not name:
        return "Please provide a name in the query parameter."

    message = f"**Hello, {name}!** Welcome to our application.\nThis is some *italic* text and **bold** text."
    html_message = markdown(message)
    return html_message

if __name__ == '__main__':
    app.run()